#include <stdio.h>
#include <ctype.h>
int main() {
    char* p = "It is 8";
    char result[100];
    int i;
    for (i = 0; p[i] != '\0'; i++) {
        if (isupper(p[i]))
            result[i] = (p[i] - 'A' + 5) % 26 + 'A';
        else if (islower(p[i]))
            result[i] = (p[i] - 'a' + 10) % 26 + 'a';
        else if (isdigit(p[i]))
            result[i] = (p[i] - '0' + 3) % 10 + '0';
        else
            result[i] = p[i];
    }
    result[i] = '\0';
    printf("%s", result);
    return 0;
}
